import { _OverlayTooltip as OverlayTooltip } from '@dynatrace/strato-components/charts';

import { restoreNullProps } from './utils/restore-null-props.js';
import { useGeoLayerTooltip } from '../../hooks/use-geo-layer-tooltip.js';
import type {
  Connection,
  ConnectionTooltipStatePayload,
} from '../../types/connection-layer.js';
import type {
  ConnectionLayerTooltipData,
  ConnectionLayerTooltipHandler,
} from '../../types/tooltip.js';
import { isDefaultTooltipHandler } from '../../utils/tooltip-type-guards.js';

export interface ConnectionLayerTooltipProps {
  tooltipTemplate?: ConnectionLayerTooltipHandler;
  hidden?: boolean;
  symbolAlignment?: 'left' | 'right';
}

export const ConnectionLayerTooltip = (props: ConnectionLayerTooltipProps) => {
  const { tooltipTemplate, hidden, symbolAlignment } = props;

  const {
    data: rawData,
    inBounds,
    position,
  } = useGeoLayerTooltip<ConnectionTooltipStatePayload>('geoConnection');

  const data = restoreNullProps(rawData);

  if (hidden || !tooltipTemplate || !inBounds || !position) {
    return null;
  }

  if (!data || !data[0]) {
    return null;
  }

  const { __lineColor: color, __lineWidth: thickness, ...rest } = data[0];
  const connectionData: ConnectionLayerTooltipData<Connection> = {
    color,
    thickness,
    data: rest as Connection,
  };

  const template = tooltipTemplate(connectionData);

  if (!template) {
    return null;
  }

  if (isDefaultTooltipHandler(tooltipTemplate)) {
    return template;
  }

  return (
    <OverlayTooltip
      legacyTemplate={template}
      symbolAlignment={symbolAlignment}
    />
  );
};

ConnectionLayerTooltip['displayName'] = 'ConnectionLayerTooltip';
